import { useState, useEffect, useCallback } from 'react'
import { Routes, Route, useNavigate } from 'react-router-dom'
import { BookOpen, FileText, Languages, ChevronRight, LayoutDashboard, Play, Pause, Square, Flame, Plus, RotateCcw, CheckCircle, Trash2, Sparkles, ArrowLeft, Volume2 } from 'lucide-react'
import API_BASE_URL from './apiConfig'
import './App.css'

const API_URL = `${API_BASE_URL}/api`

// Sound Effects - Using absolute paths for public assets
const clickSound = new Audio('/click.mp3');
const successSound = new Audio('/success.mp3');

const playSound = (audio) => {
  if (!audio) return;
  audio.currentTime = 0;
  audio.play().catch(err => console.log('Audio playback blocked by browser:', err));
};

const speak = (text) => {
  if ('speechSynthesis' in window) {
    window.speechSynthesis.cancel(); // Stop current speech
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'ja-JP';
    utterance.rate = 0.9; // Slightly slower for clarity
    window.speechSynthesis.speak(utterance);
  }
};

const Intro = ({ onFinish }) => {
  const [showButton, setShowButton] = useState(false)

  useEffect(() => {
    const timer = setTimeout(() => {
      onFinish()
    }, 2500)

    // Show button earlier during the faster animation
    const buttonTimer = setTimeout(() => {
      setShowButton(true)
    }, 1500)

    return () => {
      clearTimeout(timer)
      clearTimeout(buttonTimer)
    }
  }, [onFinish])

  return (
    <div className="intro-container">
      <svg viewBox="0 0 600 200" className="hello-svg">
        <text
          x="50%"
          y="50%"
          textAnchor="middle"
          dominantBaseline="middle"
          className="hello-text-animate"
          style={{ fontFamily: "'Caveat', cursive", fontSize: '100px' }}
        >
          Konnichiwa
        </text>
      </svg>
      {showButton && (
        <button className="get-started-btn animate-fade-in" onClick={() => onFinish()}>
          Get Started
        </button>
      )}
    </div>
  )
}

